blocks.body:
{
    "level": "B1",
    "intro": "W tym temacie nauczysz się tworzyć <strong>stronę bierną z czasownikami przyimkowymi</strong>: opiekować się, rozmawiać, płacić za i inne. Główna zasada: <strong>przyimek pozostaje z czasownikiem</strong>.",
    "rules": [
        {
            "label": "Aktywny",
            "color": "emerald",
            "text": "Stan aktywny z przyimkiem:",
            "example": "Someone looked after the children."
        },
        {
            "label": "Pasywny",
            "color": "blue",
            "text": "Przyimek bierny pozostaje:",
            "example": "The children were looked after."
        },
        {
            "label": "Reguła",
            "color": "rose",
            "text": "<strong>V + przyimek</strong> → <strong>be + V3 + przyimek</strong>",
            "example": "speak to → be spoken to"
        }
    ]
}

{
    "title": "1. Jak utworzyć stronę bierną przyimkową",
    "intro": "Forma bierna z czasownikami przyimkowymi:",
    "items": [
        {
            "label": "Formuła",
            "title": "be + V3 + przyimek",
            "subtitle": "Przyimek zawsze pozostaje na końcu"
        },
        {
            "label": "Przykład",
            "title": "opiekować się → być pod opieką",
            "subtitle": "Opiekowała się nią babcia."
        },
        {
            "label": "Nie zmieniaj się",
            "title": "Przyimek się nie porusza",
            "subtitle": "❌ Po niej się patrzyło (źle)"
        },
        {
            "label": "Agent",
            "title": "Możesz dodać „przez”",
            "subtitle": "Rozmawiała z nią menadżerka."
        }
    ]
}

{
    "title": "2. Typowe czasowniki przyimkowe",
    "sections": [
        {
            "label": "opiekować się / patrzeć",
            "color": "emerald",
            "description": "<strong>opiekować się</strong> – opiekować się. <strong>spójrz</strong> - spójrz.",
            "examples": [
                {
                    "en": "Active: Someone looks after the children.",
                    "ua": "Ktoś opiekuje się dziećmi."
                },
                {
                    "en": "Passive: The children are looked after.",
                    "ua": "Dzieci są pod opieką."
                },
                {
                    "en": "Active: Everyone looked at him.",
                    "ua": "Wszyscy na niego patrzyli."
                },
                {
                    "en": "Passive: He was looked at by everyone.",
                    "ua": "Wszyscy na niego patrzyli."
                }
            ]
        },
        {
            "label": "rozmawiać/rozmawiać o",
            "color": "blue",
            "description": "<strong>porozmawiaj z</strong> — porozmawiaj z. <strong>porozmawiaj o</strong> - porozmawiaj o.",
            "examples": [
                {
                    "en": "Active: The manager spoke to her.",
                    "ua": "Menedżer z nią rozmawiał."
                },
                {
                    "en": "Passive: She was spoken to by the manager.",
                    "ua": "Menedżer z nią rozmawiał."
                },
                {
                    "en": "Active: Everyone talks about this issue.",
                    "ua": "Wszyscy mówią o tym pytaniu."
                },
                {
                    "en": "Passive: This issue is talked about a lot.",
                    "ua": "Dużo się mówi na ten temat."
                }
            ]
        },
        {
            "label": "płacić / rozliczać się",
            "color": "sky",
            "description": "<strong>zapłacić</strong> — zapłacić za. <strong>rozliczyć</strong> — wyjaśnić.",
            "examples": [
                {
                    "en": "Active: The company paid for the training.",
                    "ua": "Firma zapłaciła za szkolenie."
                },
                {
                    "en": "Passive: The training was paid for.",
                    "ua": "Szkolenie zostało opłacone."
                },
                {
                    "en": "Active: This accounts for 50% of sales.",
                    "ua": "Stanowi to 50% sprzedaży."
                },
                {
                    "en": "Passive: 50% of sales is accounted for by this.",
                    "ua": "Stanowi 50% sprzedaży."
                }
            ]
        },
        {
            "label": "śmiać się/krzyczeć",
            "color": "amber",
            "description": "<strong>śmiać się</strong> – śmiać się z. <strong>krzycz</strong> - krzycz na.",
            "examples": [
                {
                    "en": "Active: They laughed at his joke.",
                    "ua": "Śmiali się z jego żartu."
                },
                {
                    "en": "Passive: His joke was laughed at.",
                    "ua": "Śmiali się z jego żartu."
                },
                {
                    "en": "Active: The boss shouted at him.",
                    "ua": "Szef na niego nakrzyczał."
                },
                {
                    "en": "Passive: He was shouted at by the boss.",
                    "ua": "Szef na niego nakrzyczał."
                }
            ]
        }
    ]
}

{
    "title": "3. Czasowniki frazowe w stronie biernej",
    "sections": [
        {
            "label": "Czasowniki frazowe",
            "color": "emerald",
            "description": "<strong>Czasowniki frazowe</strong> z przyimkami/imiesłami również tworzą stronę bierną.",
            "examples": [
                {
                    "en": "Active: They called off the meeting.",
                    "ua": "Odwołali spotkanie."
                },
                {
                    "en": "Passive: The meeting was called off.",
                    "ua": "Spotkanie zostało odwołane."
                },
                {
                    "en": "Active: Someone broke into the house.",
                    "ua": "Ktoś włamał się do domu."
                },
                {
                    "en": "Passive: The house was broken into.",
                    "ua": "Włamano się do domu."
                }
            ]
        },
        {
            "label": "odłożyć/odrzucić",
            "color": "blue",
            "description": "<strong>odłóż</strong> — odłóż. <strong>odrzuć</strong> – odrzuć.",
            "examples": [
                {
                    "en": "Active: They put off the decision.",
                    "ua": "Odłożyli decyzję."
                },
                {
                    "en": "Passive: The decision was put off.",
                    "ua": "Decyzję odroczono."
                },
                {
                    "en": "Active: They turned down my application.",
                    "ua": "Odrzucili mój wniosek."
                },
                {
                    "en": "Passive: My application was turned down.",
                    "ua": "Mój wniosek został odrzucony."
                }
            ]
        },
        {
            "label": "wychowywać/opiekować się",
            "color": "sky",
            "description": "<strong>wychować</strong> – wychowywać. <strong>opiekować się</strong> — dbać.",
            "examples": [
                {
                    "en": "Active: Her grandmother brought her up.",
                    "ua": "Wychowała ją babcia."
                },
                {
                    "en": "Passive: She was brought up by her grandmother.",
                    "ua": "Wychowała ją babcia."
                },
                {
                    "en": "Active: Someone took care of the problem.",
                    "ua": "Ktoś rozwiązał problem."
                },
                {
                    "en": "Passive: The problem was taken care of.",
                    "ua": "Problem został rozwiązany."
                }
            ]
        }
    ]
}

{
    "title": "4. Podsumowanie: Aktywny → Pasywny",
    "intro": "Transformacja czasowników przyimkowych:",
    "rows": [
        {
            "en": "look after",
            "ua": "opiekować się",
            "note": "The baby was looked after."
        },
        {
            "en": "speak to",
            "ua": "porozmawiać",
            "note": "She was spoken to."
        },
        {
            "en": "pay for",
            "ua": "zapłacić",
            "note": "The meal was paid for."
        },
        {
            "en": "laugh at",
            "ua": "śmiać się z",
            "note": "He was laughed at."
        },
        {
            "en": "deal with",
            "ua": "sobie poradzić",
            "note": "The issue was dealt with."
        },
        {
            "en": "refer to",
            "ua": "odnieść się do",
            "note": "This book is often referred to."
        }
    ],
    "warning": "📌 <strong>Przyimek zawsze pozostaje na końcu zdania!</strong>"
}

{
    "title": "5. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Pomijanie przyimka.",
            "wrong": "The children were looked.",
            "right": "✅ The children were looked after."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Przyimek na początku.",
            "wrong": "After the children was looked.",
            "right": "✅ The children were looked after."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Zmiana przyimka.",
            "wrong": "She was spoken with.",
            "right": "✅ She was spoken to."
        },
        {
            "label": "Błąd 4",
            "color": "rose",
            "title": "Pominięcie partykuły w czasowniku frazowym.",
            "wrong": "The meeting was called.",
            "right": "✅ The meeting was called off."
        }
    ]
}
